class Solution {
    public int maxSubstrings(String word) {
        int n = word.length();
        boolean[][] intersect = new boolean[n][n];
        for (int i = 0; i < n; i++) {
            for (int j = i + 3; j < n; j++) {
                if (word.charAt(i) == word.charAt(j)) {
                    intersect[i][j] = true;
                }
            }
        }
        int[] dp = new int[n];
        for (int i = 3; i < n; i++) {
            if (intersect[0][i]) {
                dp[i] = 1;
            }
        }
        for (int i = 4; i < n; i++) {
            for (int j = 3; j < i; j++) {
                if (intersect[j + 1][i] && dp[j] > 0 && dp[i] < dp[j] + 1) {
                    dp[i] = dp[j] + 1;
                }
            }
        }
        int max = 0;
        for (int i = 0; i < n; i++) {
            max = Math.max(max, dp[i]);
        }
        return max;
    }
}
